module top_module (
    input clk,
    input sreset,
    input [5:0] reset_value,
    output [5:0] q );reg [5:0] obf_q_reg;

    always @(posedge clk) begin
        if (sreset)
            obf_q_reg <= reset_value;
        else
            obf_q_reg <= obf_q_reg + 1;
    end

    assign q = obf_q_reg;

endmodule
